import sailpoint.object.*;


log.error("roleMap "+roleMap);

String roleName = roleMap.get("Name");

Map returnMap = new HashMap();
returnMap.put("status","success");

if (roleName.startsWith("BFR.Regional Operations")) {
	returnMap.put("errorMessage","Birthrigth roles can not be updated.");
	returnMap.put("status","Failed");
}

if (roleName.startsWith("BFR.Engineering")) {
	returnMap.put("errorMessage","Birthrigth roles can not be updated.#Invalid role to update");
	returnMap.put("status","Invalid");
}

returnMap.put("roleName",roleName);

returnMap.put("roleId","12asdasd34234asasd");



return returnMap;
